# src/integrations/zarinpal.py
import aiohttp
from typing import Tuple
from src.logger import logger

class ZarinpalGateway:
    def __init__(self, merchant_id: str, sandbox: bool = True):
        self.merchant_id = merchant_id
        self.base_url = 'https://sandbox.zarinpal.com/pg' if sandbox else 'https://www.zarinpal.com/pg'

    async def request_payment(self, amount: int, description: str) -> Tuple[bool, str]:
        """Request payment link from Zarinpal.

        Returns: (success, payment_url or error_message)
        """
        async with aiohttp.ClientSession() as session:
            payload = {
                'MerchantID': self.merchant_id,
                'Amount': amount,
                'Description': description,
                'CallbackURL': 'https://rufifo.ir/payment/callback'
            }

            try:
                async with session.post(
                    f'{self.base_url}/rest/WebGate.json',
                    json=payload,
                    timeout=aiohttp.ClientTimeout(total=10)
                ) as resp:
                    data = await resp.json()

                    if data['Status'] == 100:
                        url = f'{self.base_url}/StartPay/{data["Authority"]}'
                        return True, url
                    else:
                        return False, f'Error: {data.get("Status", "Unknown")}'

            except Exception as e:
                logger.error(f'Zarinpal error: {e}')
                return False, str(e)

    async def verify_payment(self, authority: str, amount: int) -> Tuple[bool, str]:
        """Verify payment with Zarinpal.

        Returns: (success, reference_id or error_message)
        """
        async with aiohttp.ClientSession() as session:
            payload = {
                'MerchantID': self.merchant_id,
                'Authority': authority,
                'Amount': amount
            }

            try:
                async with session.post(
                    f'{self.base_url}/rest/WebGate.json',
                    json=payload,
                    timeout=aiohttp.ClientTimeout(total=10)
                ) as resp:
                    data = await resp.json()

                    if data['Status'] == 100:
                        return True, data.get('RefID', '')
                    else:
                        return False, f'Payment failed: {data.get("Status")}'

            except Exception as e:
                logger.error(f'Zarinpal verification error: {e}')
                return False, str(e)
